<template>
    <create-form @onSubmit="submit">
        <div class="col-lg-12">
            <Fieldset>
                <template v-slot:name>Event Information</template>
                <template v-slot:content>
                    <div class="col-lg-12">
                        <div class="row g-3">
                            <div class="col-xl-3 col-lg-4">
                                <File title="Image" field="data.original_image" mime="img" fileClassName="file2"
                                    :showCrop="true" :vHeight="$root.media_validators?.image?.min_height ?? 600"
                                    :vWidth="$root.media_validators?.image?.min_width ?? 600"
                                    :vSizeInKb="$root.media_validators?.image?.max_size ?? 5000" col="12 col-12" />
                                <GlobalCrop field="data.original_image"
                                    v-on:update:modelValue="data.original_image = $event" :image="image.original_image"
                                    :aspectRatio="{
                                        aspectRatio:
                                            ($root.media_validators?.image?.min_width ?? 600) /
                                            ($root.media_validators?.image?.min_height ?? 600),
                                    }" :minWidth="$root.media_validators?.image?.min_width ?? 600"
                                    :minHeight="$root.media_validators?.image?.min_height ?? 600">
                                </GlobalCrop>
                            </div>
                            <div class="col-xl-9 col-lg-8">
                                <div class="row g-3">
                                    <Select field="data.category_id" :req="true" title="Category"
                                        v-model="data.category_id" label="title" :reduce="(obj) => obj.id"
                                        :options="categories" placeholder="--Select One--" :closeOnSelect="true"
                                        col="6 col-xl-6" />

                                    <Input v-model="data.title" field="data.title" title="Title" :req="true"
                                        col="6 col-xxl-6" />

                                    <Input v-model="data.venue" field="data.venue" title="Venue" :req="false"
                                        col="4 col-xxl-4" />

                                    <date-picker id="date3" field="data.start_date" name="start_date"
                                        v-model="data.start_date" title="Start Date" placeholder="dd/mm/yyyy"
                                        :req="true" col="4 col-xxl-4"></date-picker>

                                    <date-picker id="date4" field="data.end_date" name="end_date"
                                        v-model="data.end_date" title="End Date" placeholder="dd/mm/yyyy" :req="true"
                                        col="4 col-xxl-4"></date-picker>

                                    <Input v-model="data.highlighted_text" field="data.highlighted_text"
                                        title="Highlight" col="6 col-xxl-6" />

                                    <Input title="Sorting" field="data.sorting" v-model="data.sorting" :req="true"
                                        col="3" type="number" />
                                    <Switch col="3" v-model="data.status" on-label="Active" off-label="Deactive"
                                        :req="true">
                                    </Switch>
                                </div>
                            </div>
                            <editor title="Description" v-model="data.description" col="12" />
                        </div>
                    </div>
                </template>
            </Fieldset>
        </div>
        <div class="col-lg-12">
            <Fieldset>
                <template v-slot:name>Event</template>
                <div class="viewer_devider"></div>
                <template v-slot:content>
                    <div class="col-lg-12">
                        <div class="multiple_options_create table-responsive text-nowrap">
                            <table class="table table-bordered mb-0 mt-0">
                                <thead>
                                    <tr>
                                        <th>Date</th>
                                        <th>Schedule Time</th>
                                        <th>Event Title</th>
                                        <th>Description</th>
                                        <th>Status <sup class="text-danger">*</sup></th>
                                        <th>Action</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    <tr v-for="(schedule, index) in data.event_schedules" :key="index">
                                        <td style="width: 250px;" class="disable_label">
                                            <div class="row">
                                                <date-picker :id="`date_${index}`"
                                                    :field="`event_schedules[${index}][schedule_date]`"
                                                    :name="`event_schedules[${index}][schedule_date]`"
                                                    v-model="schedule.schedule_date" placeholder="dd/mm/yyyy" col="12">
                                                </date-picker>

                                                <!-- <input type="date" class="form-control"
                                                        v-model="schedule.schedule_date"
                                                        :name="`event_schedules[${index}][schedule_date]`"> -->
                                                <small
                                                    v-if="event_schedule_errors[index] && event_schedule_errors[index].schedule_date"
                                                    class="text-danger d-inline-block fw-medium mt-1 col-12">
                                                    {{ event_schedule_errors[index].schedule_date }}
                                                </small>
                                                <!-- <small
                                                    class="text-danger d-inline-block fw-medium mt-1">error</small> -->
                                            </div>
                                        </td>
                                        <td style="width: 200px;">
                                            <div class="form-group">
                                                <div class="input-group position-relative">
                                                    <input type="time" class="form-control"
                                                        v-model="schedule.schedule_time"
                                                        :name="`event_schedules[${index}][schedule_time]`">
                                                </div>
                                            </div>
                                            <!-- <small class="text-danger d-inline-block fw-medium mt-1">error</small> -->
                                        </td>
                                        <td style="width: 320px;">
                                            <div class="form-group">
                                                <div class="input-group position-relative">
                                                    <input type="text" class="form-control" v-model="schedule.title"
                                                        placeholder="Enter your event title"
                                                        :name="`event_schedules[${index}][title]`">
                                                </div>
                                                <small
                                                    v-if="event_schedule_errors[index] && event_schedule_errors[index].title"
                                                    class="text-danger d-inline-block fw-medium mt-1">
                                                    {{ event_schedule_errors[index].title }}
                                                </small>
                                            </div>
                                            <!-- <small class="text-danger d-inline-block fw-medium mt-1">error</small> -->
                                        </td>
                                        <td style="width: 500px;">
                                            <div class="form-group">
                                                <div class="input-group position-relative">
                                                    <textarea class="textarea-control"
                                                        placeholder="Enter your description"
                                                        v-model="schedule.description"
                                                        :name="`event_schedules[${index}][description]`"></textarea>
                                                </div>
                                            </div>
                                            <!-- <small class="text-danger d-inline-block fw-medium mt-1">error</small> -->
                                        </td>
                                        <td class="center_td_value" style="width: 180px;">
                                            <div class="form-group">
                                                <div class="status_box">
                                                    <div class="status_select">
                                                        <input class="switch" type="checkbox"
                                                            :checked="schedule.status === 'active'"
                                                            @change="toggleScheduleStatus(schedule)">
                                                    </div>
                                                    <div class="action">
                                                        <span v-if="schedule.status === 'active'"
                                                            class="active">Active</span>
                                                        <span v-else class="deactive">Deactive</span>
                                                    </div>
                                                </div>
                                            </div>
                                            <!-- <small class="text-danger d-inline-block fw-medium mt-1">error</small> -->
                                        </td>

                                        <td class="center_td_value" style="width: 100px;">
                                            <div class="multiple_fields_actions_btn d-flex align-items-center gap-2">
                                                <button type="button" class="btns delete_one" data-bs-toggle="tooltip"
                                                    data-bs-placement="top" data-bs-title="Delete" v-x-tooltip
                                                    @click.prevent="removeSchedule(index)">
                                                    <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24"
                                                        viewBox="0 0 24 24" fill="none" stroke="currentColor"
                                                        stroke-width="2" stroke-linecap="round" stroke-linejoin="round"
                                                        class="icon icon-tabler icons-tabler-outline icon-tabler-trash">
                                                        <path stroke="none" d="M0 0h24v24H0z" fill="none" />
                                                        <path d="M4 7l16 0" />
                                                        <path d="M10 11l0 6" />
                                                        <path d="M14 11l0 6" />
                                                        <path d="M5 7l1 12a2 2 0 0 0 2 2h8a2 2 0 0 0 2 -2l1 -12" />
                                                        <path d="M9 7v-3a1 1 0 0 1 1 -1h4a1 1 0 0 1 1 1v3" />
                                                    </svg>
                                                </button>
                                                <button v-if="isLastItem(data.event_schedules, index)" type="button"
                                                    class="btns add_more" data-bs-toggle="tooltip"
                                                    data-bs-placement="top" data-bs-title="Add" v-x-tooltip
                                                    @click.prevent="addSchedule">
                                                    <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24"
                                                        viewBox="0 0 24 24" fill="none" stroke="currentColor"
                                                        stroke-width="2" stroke-linecap="round" stroke-linejoin="round"
                                                        class="icon icon-tabler icons-tabler-outline icon-tabler-plus">
                                                        <path stroke="none" d="M0 0h24v24H0z" fill="none" />
                                                        <path d="M12 5v14" />
                                                        <path d="M5 12h14" />
                                                    </svg>
                                                </button>
                                            </div>
                                            <!-- <small class="text-danger d-inline-block fw-medium mt-1">error</small> -->
                                        </td>
                                    </tr>
                                </tbody>
                            </table>
                        </div>
                    </div>
                </template>
            </Fieldset>
        </div>
        <div class="col-lg-12">
            <div id="meta_box" class="static_fieldset">
                <div class="check_box style2">
                    <div class="form-check">
                        <input class="form-check-input shadow-none d-none" type="checkbox" v-model="is_meta"
                            id="flexCheckChecked1">
                        <label class="form-check-label" for="flexCheckChecked1">
                            <span class="icon"></span> Show / Hide Meta Information
                        </label>
                    </div>
                </div>
            </div>
        </div>
        <div class="col-lg-12" v-if="is_meta == true">
            <Fieldset>
                <template v-slot:name>Meta Information</template>
                <template v-slot:content>
                    <div class="row g-3">
                        <div class="col-12">
                            <v-select-container field="meta_tag" title="Meta Keywords(Optional)"
                                col="12 multiple_tags_input">
                                <v-select taggable multiple name="meta_tag" v-model="data.meta_tag" no-drop></v-select>
                            </v-select-container>
                        </div>
                        <div class="col-12">
                            <div class="form-element">
                                <label for="" class="form-label">Meta Description(Optional)</label>
                                <textarea name="meta_description" v-model="data.meta_description" class="form-control"
                                    id="" cols="30" rows="4"></textarea>
                            </div>
                        </div>
                    </div>
                </template>
            </Fieldset>
        </div>
    </create-form>
</template>

<script>
const model = "events";
import { mapState } from "vuex";
import Editor from "../../../components/Form/CKEditor";


export default {
    components: { Editor },
    computed: {
        ...mapState("category", ["categories"]),
    },
    data() {
        return {
            page_title: "",
            model: model,
            data: {
                original_image: "",
                sorting: 0,
                status: "active",
                meta_tag: null,
                event_schedules: [
                    {
                        schedule_date: "",
                        schedule_time: "",
                        title: "",
                        description: "",
                        status: "active",
                    },
                ],
            },
            is_meta: false,
            image: { original_image: "" },
            event_schedule_errors: [],
        };
    },

    provide() {
        return {
            validate: this.validation,
            data: () => this.data,
            image: this.image,
        };
    },

    methods: {
        submit: function (e) {
            let hasError = false;
            this.data.event_schedules.forEach((_, index) => {
                this.validateEventScheduleRow(index);
                if (this.event_schedule_errors[index]?.title || this.event_schedule_errors[index]?.schedule_date) {
                    hasError = true;
                }
            });
            if (hasError) {
                this.$toast("Please correct the errors before submitting", "warning");
                return;
            }

            this.$validate().then((res) => {
                const error = this.validation.countErrors();

                if (error > 0) {
                    console.log(this.validation.allErrors());
                    this.$toast(
                        "You need to fill " + error + " more empty mandatory fields",
                        "warning"
                    );
                    return false;
                }

                if (res) {
                    var form = document.getElementById("form");
                    var formData = new FormData(form);

                    const description = this.data.description
                        ? this.data.description
                        : "";

                    formData.append("status", this.data.status);
                    formData.append("description", description);
                    formData.append("category_id", this.data.category_id);

                    if (this.data.meta_tag && this.data.meta_tag.length > 0) {
                        formData.append("meta_tag", JSON.stringify(this.data.meta_tag));
                    } else {
                        formData.append("meta_tag", JSON.stringify([]));
                    }

                    if (this.data.original_image) {
                        formData.append("image_base64", this.data.original_image);
                    }
                    formData.append("image_resize_value", this.$root.media_validators?.image?.resize_value ?? "");

                    this.data.event_schedules.forEach((schedule, index) => {

                        if (schedule.schedule_date) {
                            formData.append(`event_schedules[${index}][schedule_date]`, schedule.schedule_date);
                        }

                        if (schedule.schedule_time) {
                            formData.append(`event_schedules[${index}][schedule_time]`, schedule.schedule_time);
                        }

                        if (schedule.title) {
                            formData.append(`event_schedules[${index}][title]`, schedule.title);
                        }

                        if (schedule.description) {
                            formData.append(`event_schedules[${index}][description]`, schedule.description);
                        }

                        if (schedule.status) {
                            formData.append(`event_schedules[${index}][status]`, schedule.status);
                        }
                    });


                    if (this.data.id) {
                        this.update(this.model, formData, this.data.id, "image");
                    } else {
                        this.store(this.model, formData);
                    }
                }
            });
        },
        addSchedule() {
            this.data.event_schedules.push({
                schedule_date: '',
                schedule_time: '',
                title: '',
                description: '',
                status: 'active',
            });
        },
        removeSchedule(index) {
            if (this.data.event_schedules.length > 1) {
                this.data.event_schedules.splice(index, 1);
            }
        },
        isLastItem(data, index) {
            return index === data.length - 1;
        },
        toggleScheduleStatus(schedule) {
            schedule.status = schedule.status === 'active' ? 'deactive' : 'active';
        },
        
        // track of metaut
        updateIsMeta() {
            this.is_meta = !!(this.data.meta_tag && this.data.meta_tag.length > 0) ||
                !!(this.data.meta_description && this.data.meta_description.trim() !== '');
        },

        validateEventScheduleRow(index) {
            if (!this.event_schedule_errors[index]) {
                this.event_schedule_errors[index] = {};
            }

            const schedule_time = this.data.event_schedules[index].schedule_time;
            const description = this.data.event_schedules[index].description;

            const schedule_date = this.data.event_schedules[index].schedule_date;
            const title = this.data.event_schedules[index].title;

            if (schedule_time || description) {
                if (!title) {
                    this.event_schedule_errors[index].title = "Title is required";
                } else {
                    this.event_schedule_errors[index].title = ""; // Clear the error if resolved
                }

                if (!schedule_date) {
                    this.event_schedule_errors[index].schedule_date = "Schedule date is required";
                } else {
                    this.event_schedule_errors[index].schedule_date = ""; // Clear the error if resolved
                }
            }
        },
    },
    watch: {
        'data.meta_tag': function (newVal) {
            this.updateIsMeta();
        },
        'data.meta_description': function (newVal) {
            this.updateIsMeta();
        },

        "data.event_schedules": {
            handler() {
                this.data.event_schedules.forEach((_, index) => {
                    this.validateEventScheduleRow(index);
                })
            },
            deep: true,
        },

        is_meta(newVal) {
            if (newVal === true) {
                this.scrollToTag('#meta_box');
            }
        },
    },
    created() {
        this.updateIsMeta();
        if (this.$route.params.id) {
            this.get_data(`${this.model}/${this.$route.params.id}`);
            this.page_title = "Event Edit";

        } else {
            this.get_sorting("Events");
            this.page_title = "Event Create";

        }
        this.$store.dispatch("category/getCategory", { transfer: "Events" });
        this.getMediaValidators("Events");
    },

    validators: {
        "data.title": function (value = null) {
            return Validator.value(value).required("Title is required");
        },
        "data.category_id": function (value = null) {
            return Validator.value(value).required("Category is required");
        },
        "data.original_image": function (value = null) {
            return Validator.value(value);
        },
        "data.start_date": function (value = null) {
            return Validator.value(value).required("Start date is required");
        },
        "data.end_date": function (value = null) {
            const that = this;
            return Validator.value(value)
                .required("End date is required")
                .custom(function () {
                    if (!Validator.isEmpty(value) && that.data.start_date) {
                        const end = new Date(value);
                        const start = new Date(that.data.start_date);
                        if (start > end) {
                            return "End date must be later than the start date";
                        }
                    }
                });
        },
        "data.sorting": function (value = null) {
            return Validator.value(value)
                .digit()
                .regex("^[0-9]*$")
                .required("Sorting is required");
        },
        "data.status": function (value = null) {
            return Validator.value(value).required("Status is required");
        },
    },
};
</script>
